*******************************************************************************;
* Program:      suppdm.sas
* Description:  Create SDTM SUPPDM (Supplemental DM) domain
* Study:        CDISCPILOT01
* Standard:     SDTM IG v3.1.2
*******************************************************************************;

%let studyid = CDISCPILOT01;

*--- Read raw supplemental DM data ---;
data raw_suppdm;
    length STUDYID $12 SITEID $3 SUBJID $4 
           QNAM $8 QVAL $200 QLABEL $40;
    infile datalines dsd truncover;
    input STUDYID $ SITEID $ SUBJID $ QNAM $ QVAL $ QLABEL $;
    datalines;
;
run;

*--- Alternative: Read from external source if available ---;
%macro read_raw_suppdm;
    %if %sysfunc(exist(rawdata.suppdm_raw)) %then %do;
        data raw_suppdm;
            set rawdata.suppdm_raw;
        run;
    %end;
    %else %if %sysfunc(fileexist("&rawpath/suppdm.csv")) %then %do;
        proc import datafile="&rawpath/suppdm.csv"
            out=raw_suppdm
            dbms=csv
            replace;
            guessingrows=max;
        run;
    %end;
%mend read_raw_suppdm;

%read_raw_suppdm;

*--- Derive USUBJID ---;
data suppdm_usubjid;
    set raw_suppdm;
    length USUBJID $11;
    USUBJID = catx('-', STUDYID, SITEID, SUBJID);
run;

*--- Create SUPPDM structure with required variables ---;
data suppdm_base;
    length STUDYID $12
           RDOMAIN $2
           USUBJID $11
           IDVAR $8
           IDVARVAL $11
           QNAM $8
           QLABEL $40
           QVAL $200
           QORIG $8
           QEVAL $20;

    set suppdm_usubjid;

    * Set domain-related variables;
    STUDYID = "&studyid";
    RDOMAIN = "DM";
    IDVAR = "USUBJID";
    IDVARVAL = USUBJID;

    * Set origin and evaluator;
    if missing(QORIG) then QORIG = "CRF";
    if missing(QEVAL) then QEVAL = "";

    * Ensure QNAM and QLABEL are populated;
    if missing(QNAM) then delete;

    keep STUDYID RDOMAIN USUBJID IDVAR IDVARVAL QNAM QLABEL QVAL QORIG QEVAL;
run;

*--- Sort by USUBJID and QNAM for sequence numbering ---;
proc sort data=suppdm_base;
    by USUBJID QNAM;
run;

*--- Derive SUPPDMSEQ (sequential numbering per subject) ---;
data suppdm_seq;
    set suppdm_base;
    by USUBJID;

    retain SUPPDMSEQ;

    if first.USUBJID then SUPPDMSEQ = 1;
    else SUPPDMSEQ + 1;
run;

*--- Apply variable attributes per SDTM specification ---;
data suppdm;
    attrib
        STUDYID   length=$12  label="Study Identifier"
        RDOMAIN   length=$2   label="Related Domain Abbreviation"
        USUBJID   length=$11  label="Unique Subject Identifier"
        IDVAR     length=$8   label="Identifying Variable"
        IDVARVAL  length=$11  label="Identifying Variable Value"
        QNAM      length=$8   label="Qualifier Variable Name"
        QLABEL    length=$40  label="Qualifier Variable Label"
        QVAL      length=$200 label="Data Value"
        QORIG     length=$8   label="Origin"
        QEVAL     length=$20  label="Evaluator"
        SUPPDMSEQ length=8    label="Sequence Number";

    set suppdm_seq;

    * Ensure proper ordering of variables;
    keep STUDYID RDOMAIN USUBJID IDVAR IDVARVAL QNAM QLABEL QVAL QORIG QEVAL SUPPDMSEQ;
run;

*--- Sort final dataset ---;
proc sort data=suppdm;
    by STUDYID USUBJID SUPPDMSEQ;
run;

*--- Create permanent SAS dataset ---;
data sdtm.suppdm;
    set suppdm;
run;

*--- Create XPT transport file ---;
libname xptout xport "&outpath/sdtm/suppdm.xpt";

data xptout.suppdm;
    set sdtm.suppdm;
run;

libname xptout clear;

*--- Generate summary report ---;
proc sql noprint;
    select count(*) into :nobs trimmed
    from sdtm.suppdm;

    select count(distinct USUBJID) into :nsubj trimmed
    from sdtm.suppdm;

    select count(distinct QNAM) into :nqnam trimmed
    from sdtm.suppdm;
quit;

proc freq data=sdtm.suppdm;
    tables QNAM*QLABEL / list missing;
    title "SUPPDM Domain - Qualifier Variable Frequency";
run;

proc print data=sdtm.suppdm(obs=10);
    title "SUPPDM Domain - First 10 Records";
run;

%put NOTE: SUPPDM domain created successfully;
%put NOTE: Total records: &nobs;
%put NOTE: Total subjects: &nsubj;
%put NOTE: Total qualifiers: &nqnam;

title;
